In this code, which component is prop drilling (passing a prop through without using it)?

```jsx
function App() {
  return <Layout username="Casey" />;
}

function Layout({ username }) {
  return (
    <div>
      <Sidebar username={username} />
      <main>Content here</main>
    </div>
  );
}

function Sidebar({ username }) {
  return (
    <aside>
      <p>Logged in as: {username}</p>
    </aside>
  );
}
```

The OrderConfirmation component shows the wrong total. Where would you look to find the bug?

```jsx
function CheckoutFlow() {
  const order = {
    items: ["Widget A", "Widget B"],
    subtotal: 59.98,
    tax: 4.80,
    total: 64.78,
  };

  return (
    <div>
      <OrderSummary subtotal={order.subtotal} tax={order.tax} />
      <OrderConfirmation amount={order.subtotal} />
    </div>
  );
}

function OrderConfirmation({ amount }) {
  return <p>Your total: ${amount}</p>;
}
```
